mapper.select:
SELECT B1.* FROM ( SELECT A1.*, ROW_NUMBER() OVER( ORDER BY
A1."requestDt" DESC, A1."requestNo" DESC
A1."${sortColumn}" ${order}
) AS PAGEINDEX FROM ( SELECT 'PEERREVIEW' AS "objectType", 'Peer Review' AS "objectTypeNm", 'DISTRIBUTION' AS "requestType", '배포' AS "requestTypeNm", info.peerreview_no AS "requestNo", info.peerreview_no AS "requestOrgNo", info.peerreview_no AS "peerreviewNo", info.peerreview_no AS "peerReviewNo", info.peerreview_no AS "peerreview_no", info.peerreview_no AS "objectNo", info.peerreview_nm AS "title", info.peerreview_nm AS "peerreviewNm", info.peerreview_nm AS "peerReviewNm", info.peerreview_nm AS "peerreview_nm", info.peerreview_nm AS "objectNm", info.peerreview_nm AS "peerReviewTitle", info.peerreview_nm AS "peerreviewTitle", COALESCE(info.status, '') AS "statusCd", COALESCE(info.status, '') AS "statusNm", COALESCE(info.status, '') AS "status", info.insert_dt AS "requestDt", info.insert_dt AS "insertDt", info.insert_dt AS "insert_dt", COALESCE(info.reviewdate, '') AS "reviewdate", COALESCE(info.reviewdate, '') AS "reviewDate", info.insert_uid AS "insertUid", COALESCE(info.insert_user_nm, '') AS "insertUserNm", COALESCE(info.approver, '') AS "approver", COALESCE(info.approver, '') AS "reviewerUser", COALESCE(info.approved_users, '') AS "approvedUsers", COALESCE(info.processing_status, '') AS "processingStatus", info.object_id AS "objectId", info.object_id AS "hiddenObjectId", COALESCE(info.rev_no, '') AS "revNo" FROM docs_peerreview info WHERE COALESCE(info.deleted_yn, 'N') = 'N'
AND info.peerreview_no ILIKE CONCAT('%', #{peerreviewNo}, '%')
AND info.peerreview_nm ILIKE CONCAT('%', #{peerreviewNm}, '%')
AND info.status = #{statusCd}
AND info.insert_dt BETWEEN TO_DATE(#{requestStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{requestEndDt}, 'YYYY-MM-DD') + INTERVAL '1 DAY'
) A1 ) B1 WHERE 1=1
AND PAGEINDEX <= #{end}
AND PAGEINDEX >= #{start}

mapper.update:
UPDATE docs_peerreview
   SET approved_users = #{approvedUsers},
       status = #{status}
 WHERE object_id = #{objectId}
   AND COALESCE(deleted_yn, 'N') = 'N'

UPDATE docs_peerreview
   SET processing_status = #{processingStatus}
 WHERE object_id = #{objectId}
   AND COALESCE(deleted_yn, 'N') = 'N'
